package com.democorp.dfp.execution;

/** Synthetic DFP code for DREAM codebase memory demos. */
public class ExecutionService { private final StatusTracker statusTracker = new StatusTracker(); private final BatchJobAdapter batchJobAdapter = new BatchJobAdapter(); private final OutputCollector outputCollector = new OutputCollector(); public Execution startExecution(String jobId, TaskType firstTaskType) { Execution execution = new Execution(); execution.executionId = "exec-" + jobId; execution.jobId = jobId; statusTracker.markExecutionQueued(execution.executionId); statusTracker.markExecutionRunning(execution.executionId); if (firstTaskType == TaskType.BATCH_TASK) { batchJobAdapter.submitBatchTask(execution.executionId, "task-forecast-batch"); } return execution; } public ExecutionStatus resolveFinalStatus(boolean criticalTaskFailed, boolean optionalTaskFailed) { if (criticalTaskFailed) { return ExecutionStatus.FAILED; } if (optionalTaskFailed) { return ExecutionStatus.PARTIAL_SUCCESS; } return ExecutionStatus.COMPLETED; } public void collectOutputsAfterCompletion(String executionId) { outputCollector.collectForExecution(executionId, "task-forecast-batch", "attempt-1"); } }
